import{_ as s,o as n,c as r,O as e}from"./chunks/framework.47655c42.js";const b=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1775907908000}'),c={name:"guide/faq.md"};function d(t,a,l,i,p,_){return n(),r("div",null,a[0]||(a[0]=[e('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">FAQ</p><h1>常见问题</h1><div class="brand-hero__panel"><span class="brand-pill">Key Questions</span><strong>很多疑问都集中在定位、隔离、热更新和 CLI 这些核心问题上。</strong><p>集中回答公开沟通中最常见的问题。</p></div><p class="brand-lead"> 这一页专门回答第一次沟通、第一次体验和第一次做交付时最容易问到的问题。 它的目标不是讲概念，而是把<strong>定位、边界、隔离、热更新、CLI、本地执行和当前阶段</strong>一次说清楚。 </p><div class="brand-chip-list"><span class="brand-chip">定位</span><span class="brand-chip">隔离</span><span class="brand-chip">热更新</span><span class="brand-chip">CLI / Agent</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="../product/index.html">看产品概览</a><a class="cta-button" href="../contact.html#lead-form">联系与试用</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // FAQ</span><span>GUIDE 03</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__value matrix-panel__fn">positioning</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__fn">boundary</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__fn">current_stage</span></span><span class="matrix-panel__line"><span class="matrix-panel__value matrix-panel__ident">tenant_isolation</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">hot_update</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">public_safe_docs</span></span><span class="matrix-panel__line"><span class="matrix-panel__value matrix-panel__ident">cli_bridge</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">local_execution</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">team_delivery</span></span></div><div class="matrix-panel__callout">CLEAR BOUNDARIES SAVE EVERYONE TIME</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">faq</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">current</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">tone</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">direct</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">scope</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">public_safe</span></span></div></div></div></section><section class="brand-card"><p class="brand-kicker">Positioning</p><h2>定位相关</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>它是不是一个普通聊天系统</h3><p>不是。它是一个让 AI 在规则内调用和执行真实能力的平台，当前最成熟的执行资产是 Python 脚本。</p></article><article class="brand-card brand-card--nested"><h3>它适合哪些人</h3><p>适合已经有脚本、自动化任务、数据处理需求，或需要把这些能力变成统一入口、统一交付和统一治理的人。</p></article><article class="brand-card brand-card--nested"><h3>免费版是不是企业后台裁剪版</h3><p>不是。免费版面向个人探索者，用来快速体验能力接入、AI 调度与执行反馈；团队与企业场景再进入更完整的协作和治理路径。</p></article><article class="brand-card brand-card--nested"><h3>企业线和免费线是不是两套完全分裂的系统</h3><p>不是。它们共享同一套执行与安全底座，只是面向的使用规模、协作深度和交付方式不同。</p></article></div></section><section class="brand-card"><p class="brand-kicker">Safety</p><h2>安全、隔离与权限边界</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>AI 会不会越权执行</h3><p>当前平台强调 AI 在规则内工作。推荐范围、执行边界、人工确认和审计留痕都不是可有可无的装饰层。</p></article><article class="brand-card brand-card--nested"><h3>一个客户能不能看到另一个客户的能力</h3><p>不能。当前正式交付模型是一个客户一个租户，客户默认只能看到自己租户内被授权的能力。</p></article><article class="brand-card brand-card--nested"><h3>平台如何保证不同客户之间隔离</h3><p>平台默认按客户边界隔离能力、数据和权限，确保不同客户之间互不可见、互不干扰。</p></article><article class="brand-card brand-card--nested"><h3>AI 会不会跨租户推荐别的客户能力</h3><p>不会。当前推荐范围受租户与权限共同约束，不是“模型想到什么就推什么”。</p></article></div></section><section class="brand-card"><p class="brand-kicker">Delivery</p><h2>交付与热更新</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>是不是一定要私有化才能用</h3><p>不一定。可以根据数据边界、客户规模和执行位置，选择单租户交付、平台治理组合或混合执行路径。</p></article><article class="brand-card brand-card--nested"><h3>热更新是不是要重部署整个平台</h3><p>不是。客户脚本通过审核、同步、注册和授权后，可以在当前租户内生效，不需要整个平台重新部署。</p></article><article class="brand-card brand-card--nested"><h3>客户能不能自己上传脚本后直接正式上线</h3><p>当前 <code>1.0</code> 默认不这样做。平台仍保留审核、注册、授权和权限验证流程，不支持绕过平台直接正式上线。</p></article><article class="brand-card brand-card--nested"><h3>热更新会不会影响其他客户</h3><p>不会。脚本更新后只在所属租户范围内生效，其他租户不会自动获得可见或可执行权限。</p></article><article class="brand-card brand-card--nested"><h3>是不是所有项目都默认包含文件上传和结果下载</h3><p>不一定。如果项目需要处理输入文件和结果产物，平台可以提供文件上传、批次状态和结果下载链路；是否开放以具体项目范围为准。</p></article><article class="brand-card brand-card--nested"><h3>正式交付后客户通常会拿到哪些说明</h3><p>通常至少包括访问入口、账号方式、客户使用说明、客户脚本热更新说明；如果项目包含公告、客户须知或结果下载入口，也应一起交待清楚。</p></article></div></section><section class="brand-card"><p class="brand-kicker">CLI &amp; Local</p><h2>CLI、本地脚本和 Agent</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>CLI 现在是不是概念功能</h3><p>不是。<code>execgov-cli</code> 已支持 <code>login</code>、<code>register</code>、<code>list</code>、<code>run</code>、<code>agent describe</code> 和 <code>agent start</code>，适合本地接入、调试和试用。</p></article><article class="brand-card brand-card--nested"><h3>本地 Agent 是不是已经正式商用</h3><p>还不是。本地 Agent 相关能力仍在持续完善，目前可以先按本地桥接与执行骨架理解。</p></article><article class="brand-card brand-card--nested"><h3>本地脚本和内网资源能不能接入平台</h3><p>可以，但通常不是让浏览器直接碰本地路径，而是通过 CLI / Agent 路线承接本地执行桥接。</p></article><article class="brand-card brand-card--nested"><h3>是不是所有脚本类型都已经完整支持远程入库</h3><p>远程注册目前主要围绕 Python 脚本，更多类型会继续扩展。</p></article></div></section><section class="brand-card"><p class="brand-kicker">Stage</p><h2>当前阶段与升级路径</h2><div class="brand-grid brand-grid--two"><article class="brand-card brand-card--nested"><h3>现在已经做出什么</h3><p>企业 <code>1.0</code> 交付主线、个人免费入口、CLI 最小桥梁能力和外部文档都已可用，可以支撑演示、试用和部分真实场景。</p></article><article class="brand-card brand-card--nested"><h3>标准化小团队方案是不是已经完全开放</h3><p>标准化小团队方案、套餐化和更完整的产品能力会继续扩展。</p></article><article class="brand-card brand-card--nested"><h3>体验页适合帮我判断什么</h3><p>它适合先感受执行链路、理解平台定位，并判断自己更适合个人注册、团队试用还是企业咨询。</p></article><article class="brand-card brand-card--nested"><h3>注册成功后会去哪里</h3><p>当前成功后由提示框承接，再跳回登录页，而不是跳到独立欢迎页。</p></article></div></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>FAQ 后的常用入口</h2><p class="brand-lead">可按目标继续查看产品概览、客户交付、CLI，或直接提交试用 / 咨询线索。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="../product/index.html"><span>Product</span><strong>产品概览</strong></a><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>客户流程 / 交付</strong></a><a class="brand-link-card" href="../product/cli.html"><span>CLI</span><strong>CLI 指引</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>联系与试用</strong></a></div></div></section></div>',1)]))}const h=s(c,[["render",d]]);export{b as __pageData,h as default};
